/**
 * CipherLink — Browser Crypto Utilities (Web Crypto API)
 *
 * All private key operations happen exclusively in the browser.
 * Private keys are stored only in sessionStorage and NEVER sent to the server.
 *
 * Algorithms:
 *   RSA-OAEP 2048  — encrypt AES session key for recipient
 *   RSA-PSS  2048  — digital signature (sender authentication)
 *   ECDH P-256     — ephemeral shared-key derivation (forward secrecy)
 *   AES-256-GCM    — authenticated symmetric encryption
 *   SHA-256        — message integrity hash
 */

const subtle = window.crypto.subtle;

// ── Encoding helpers ────────────────────────────────────────────────────────

export const buf2b64 = buf => btoa(String.fromCharCode(...new Uint8Array(buf)));
export const b642buf = b64 => Uint8Array.from(atob(b64), c => c.charCodeAt(0)).buffer;
export const str2buf = str => new TextEncoder().encode(str);
export const buf2str = buf => new TextDecoder().decode(buf);
export const generateNonce = () => buf2b64(window.crypto.getRandomValues(new Uint8Array(16)));

// ── SHA-256 ─────────────────────────────────────────────────────────────────

export async function sha256(text) {
  const digest = await subtle.digest('SHA-256', str2buf(text));
  return Array.from(new Uint8Array(digest)).map(b => b.toString(16).padStart(2, '0')).join('');
}

// ── RSA-OAEP (encrypt / decrypt AES key) ────────────────────────────────────

export const generateRSAKeyPair = () => subtle.generateKey({
  name: 'RSA-OAEP',
  modulusLength: 2048,
  publicExponent: new Uint8Array([1, 0, 1]),
  hash: 'SHA-256'
}, true, ['encrypt', 'decrypt']);
export async function exportPublicKeyPEM(key) {
  const spki = await subtle.exportKey('spki', key);
  const b64 = buf2b64(spki);
  return `-----BEGIN PUBLIC KEY-----\n${b64.match(/.{1,64}/g).join('\n')}\n-----END PUBLIC KEY-----`;
}
export async function importPublicKeyOAEP(pem) {
  const b64 = pem.replace(/-----[^-]+-----/g, '').replace(/\s/g, '');
  return subtle.importKey('spki', b642buf(b64), {
    name: 'RSA-OAEP',
    hash: 'SHA-256'
  }, true, ['encrypt']);
}
export async function encryptAESKey(recipientPub, aesKey) {
  const raw = await subtle.exportKey('raw', aesKey);
  return buf2b64(await subtle.encrypt({
    name: 'RSA-OAEP'
  }, recipientPub, raw));
}
export async function decryptAESKey(myPriv, encB64) {
  const raw = await subtle.decrypt({
    name: 'RSA-OAEP'
  }, myPriv, b642buf(encB64));
  return subtle.importKey('raw', raw, {
    name: 'AES-GCM'
  }, false, ['encrypt', 'decrypt']);
}

// ── RSA-PSS (sign / verify) ──────────────────────────────────────────────────

export const generateRSASignKeyPair = () => subtle.generateKey({
  name: 'RSA-PSS',
  modulusLength: 2048,
  publicExponent: new Uint8Array([1, 0, 1]),
  hash: 'SHA-256'
}, true, ['sign', 'verify']);
export async function exportSignPublicKeyPEM(key) {
  const spki = await subtle.exportKey('spki', key);
  const b64 = buf2b64(spki);
  return `-----BEGIN PUBLIC KEY-----\n${b64.match(/.{1,64}/g).join('\n')}\n-----END PUBLIC KEY-----`;
}
export async function importSignPublicKey(pem) {
  const b64 = pem.replace(/-----[^-]+-----/g, '').replace(/\s/g, '');
  return subtle.importKey('spki', b642buf(b64), {
    name: 'RSA-PSS',
    hash: 'SHA-256'
  }, true, ['verify']);
}
export async function signMessage(privSign, messageHash) {
  const sig = await subtle.sign({
    name: 'RSA-PSS',
    saltLength: 32
  }, privSign, str2buf(messageHash));
  return buf2b64(sig);
}
export async function verifySignature(pubSign, messageHash, sigB64) {
  try {
    return await subtle.verify({
      name: 'RSA-PSS',
      saltLength: 32
    }, pubSign, b642buf(sigB64), str2buf(messageHash));
  } catch {
    return false;
  }
}

// ── ECDH P-256 ───────────────────────────────────────────────────────────────

export const generateECDHKeyPair = () => subtle.generateKey({
  name: 'ECDH',
  namedCurve: 'P-256'
}, true, ['deriveKey']);
export async function exportECDHPublicKeyPEM(key) {
  const spki = await subtle.exportKey('spki', key);
  const b64 = buf2b64(spki);
  return `-----BEGIN PUBLIC KEY-----\n${b64.match(/.{1,64}/g).join('\n')}\n-----END PUBLIC KEY-----`;
}
export async function importECDHPublicKey(pem) {
  const b64 = pem.replace(/-----[^-]+-----/g, '').replace(/\s/g, '');
  return subtle.importKey('spki', b642buf(b64), {
    name: 'ECDH',
    namedCurve: 'P-256'
  }, true, []);
}
export const deriveSharedAESKey = (myPriv, theirPub) => subtle.deriveKey({
  name: 'ECDH',
  public: theirPub
}, myPriv, {
  name: 'AES-GCM',
  length: 256
}, false, ['encrypt', 'decrypt']);

// ── AES-256-GCM ──────────────────────────────────────────────────────────────

export async function aesEncrypt(aesKey, plaintext) {
  const iv = window.crypto.getRandomValues(new Uint8Array(12));
  const enc = await subtle.encrypt({
    name: 'AES-GCM',
    iv
  }, aesKey, str2buf(plaintext));
  const out = new Uint8Array(12 + enc.byteLength);
  out.set(iv, 0);
  out.set(new Uint8Array(enc), 12);
  return buf2b64(out.buffer);
}
export async function aesDecrypt(aesKey, encB64) {
  const data = new Uint8Array(b642buf(encB64));
  const dec = await subtle.decrypt({
    name: 'AES-GCM',
    iv: data.slice(0, 12)
  }, aesKey, data.slice(12));
  return buf2str(dec);
}

// ── Key persistence (sessionStorage) ─────────────────────────────────────────

export async function saveKeysToSession(rsaEncPair, rsaSignPair, ecdhPair) {
  sessionStorage.setItem('cl_priv_encrypt', buf2b64(await subtle.exportKey('pkcs8', rsaEncPair.privateKey)));
  sessionStorage.setItem('cl_priv_sign', buf2b64(await subtle.exportKey('pkcs8', rsaSignPair.privateKey)));
  sessionStorage.setItem('cl_priv_ecdh', buf2b64(await subtle.exportKey('pkcs8', ecdhPair.privateKey)));
}
export async function loadKeysFromSession() {
  const e = sessionStorage.getItem('cl_priv_encrypt');
  const s = sessionStorage.getItem('cl_priv_sign');
  const d = sessionStorage.getItem('cl_priv_ecdh');
  if (!e || !s || !d) return null;
  return {
    privateEncryptKey: await subtle.importKey('pkcs8', b642buf(e), {
      name: 'RSA-OAEP',
      hash: 'SHA-256'
    }, false, ['decrypt']),
    privateSignKey: await subtle.importKey('pkcs8', b642buf(s), {
      name: 'RSA-PSS',
      hash: 'SHA-256'
    }, false, ['sign']),
    privateECDHKey: await subtle.importKey('pkcs8', b642buf(d), {
      name: 'ECDH',
      namedCurve: 'P-256'
    }, false, ['deriveKey'])
  };
}

// ── Full encrypt / decrypt pipeline ──────────────────────────────────────────

export async function encryptMessage({
  plaintext,
  myPrivateSignKey,
  myPrivateECDHKey,
  recipientECDHPublicKeyPEM,
  recipientRSAPublicKeyPEM
}) {
  const theirECDH = await importECDHPublicKey(recipientECDHPublicKeyPEM);
  const sharedAES = await deriveSharedAESKey(myPrivateECDHKey, theirECDH);
  const enc_content = await aesEncrypt(sharedAES, plaintext);
  const theirRSA = await importPublicKeyOAEP(recipientRSAPublicKeyPEM);
  const enc_aes_key = await encryptAESKey(theirRSA, sharedAES);
  const msg_hash = await sha256(plaintext);
  const signature = await signMessage(myPrivateSignKey, msg_hash);
  return {
    encrypted_content: enc_content,
    encrypted_aes_key: enc_aes_key,
    message_hash: msg_hash,
    signature,
    nonce: generateNonce()
  };
}
export async function decryptMessage({
  encryptedMsg,
  myPrivateECDHKey,
  senderECDHPublicKeyPEM,
  senderRSASignPublicKeyPEM
}) {
  const theirECDH = await importECDHPublicKey(senderECDHPublicKeyPEM);
  const sharedAES = await deriveSharedAESKey(myPrivateECDHKey, theirECDH);
  let plaintext;
  try {
    plaintext = await aesDecrypt(sharedAES, encryptedMsg.encrypted_content);
  } catch {
    return {
      plaintext: '[Decryption failed]',
      verified: false,
      hashOk: false
    };
  }
  const hashOk = (await sha256(plaintext)) === encryptedMsg.message_hash;
  let verified = false;
  try {
    const pub = await importSignPublicKey(senderRSASignPublicKeyPEM);
    verified = await verifySignature(pub, encryptedMsg.message_hash, encryptedMsg.signature);
  } catch {}
  return {
    plaintext,
    verified,
    hashOk
  };
}

